struct PasswordResetView: View {
    let token: String
    @State private var newPassword = ""
    @State private var confirmPassword = ""
    @State private var isSubmitting = false
    @State private var errorMessage: String?
    @State private var successMessage: String?

    var body: some View {
        NavigationStack {
            Form {
                Section("Reset Password") {
                    SecureField("New Password", text: $newPassword)
                    SecureField("Confirm Password", text: $confirmPassword)
                }

                if let errorMessage {
                    Section {
                        Text(errorMessage)
                            .foregroundStyle(.red)
                    }
                }

                if let successMessage {
                    Section {
                        Text(successMessage)
                            .foregroundStyle(.green)
                    }
                }

                Section {
                    Button(isSubmitting ? "Submitting..." : "Reset Password") {
                        submit()
                    }
                    .disabled(isSubmitting || newPassword.isEmpty || confirmPassword.isEmpty)
                }
            }
            .navigationTitle("Reset Password")
        }
    }

    private func submit() {
        guard newPassword == confirmPassword else {
            errorMessage = "Passwords do not match."
            successMessage = nil
            return
        }

        isSubmitting = true
        errorMessage = nil
        successMessage = nil

        Task {
            do {
                try await PasswordResetAPI.shared.resetPassword(token: token, newPassword: newPassword)
                await MainActor.run {
                    isSubmitting = false
                    successMessage = "Your password has been reset."
                }
            } catch {
                await MainActor.run {
                    isSubmitting = false
                    errorMessage = "Failed to reset password."
                }
            }
        }
    }
}

final class PasswordResetAPI {
    static let shared = PasswordResetAPI()
    private init() {}

    func resetPassword(token: String, newPassword: String) async throws {
        guard let url = URL(string: "https://myapp.com/api/reset-password") else { return }
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")

        let payload: [String: String] = [
            "token": token,
            "newPassword": newPassword
        ]
        request.httpBody = try JSONSerialization.data(withJSONObject: payload, options: [])

        _ = try await URLSession.shared.data(for: request)
    }
}

